var COURSE_PL_DE = [{day: 1, title: `Pierwsze powitania`, title_native: `Erste Begrüßungen`, focus: `Nauczysz się witać, żegnać i mówić proste uprzejmości w Berlinie. To pierwszy krok do swobodnego kontaktu w hotelu, kawiarni i na ulicy.`, vocab: [{de: `Hallo`, pl: `cześć`, ipa: `[ha-lo]`},{de: `Guten Morgen`, pl: `dzień dobry rano`, ipa: `[gu-ten mor-gen]`},{de: `Guten Tag`, pl: `dzień dobry`, ipa: `[gu-ten tak]`},{de: `Guten Abend`, pl: `dobry wieczór`, ipa: `[gu-ten a-bent]`},{de: `Tschüss`, pl: `pa`, ipa: `[czys]`},{de: `Auf Wiedersehen`, pl: `do widzenia`, ipa: `[ałf wi-der-ze-en]`},{de: `bitte`, pl: `proszę`, ipa: `[bi-te]`},{de: `danke`, pl: `dziękuję`, ipa: `[dan-ke]`},{de: `ja`, pl: `tak`, ipa: `[ja]`},{de: `nein`, pl: `nie`, ipa: `[najn]`}], phrases: [{de: `Hallo, guten Tag.`, pl: `Cześć, dzień dobry.`, ipa: `[ha-lo, gu-ten tak]`},{de: `Danke schön.`, pl: `Bardzo dziękuję.`, ipa: `[dan-ke szyn]`},{de: `Bitte schön.`, pl: `Proszę bardzo.`, ipa: `[bi-te szyn]`},{de: `Auf Wiedersehen.`, pl: `Do widzenia.`, ipa: `[ałf wi-der-ze-en]`},{de: `Ja, bitte.`, pl: `Tak, proszę.`, ipa: `[ja, bi-te]`},{de: `Nein, danke.`, pl: `Nie, dziękuję.`, ipa: `[najn, dan-ke]`}], grammar: `W języku niemieckim rzeczowniki pisze się wielką literą, ale na razie skup się na gotowych zwrotach. „Guten Tag” jest bezpieczne w prawie każdej sytuacji formalnej. „Hallo” jest bardziej swobodne i pasuje do sklepu, hostelu albo rozmowy z młodszą osobą.`, practice: [`Przywitaj recepcjonistę w hotelu słowami „Guten Tag”.`,`Powiedz „dziękuję bardzo” po niemiecku.`,`Pożegnaj się formalnie z pracownikiem informacji turystycznej.`,`Odpowiedz „tak, proszę” na pytanie, czy chcesz mapę.`,`Odpowiedz „nie, dziękuję” na propozycję torby w sklepie.`]},{day: 2, title: `Przedstawianie się`, title_native: `Sich vorstellen`, focus: `W Monachium przy meldowaniu albo podczas wycieczki grupowej przyda się umiejętność powiedzenia, kim jesteś. Nauczysz się podawać imię, kraj i podstawowe informacje.`, vocab: [{de: `ich`, pl: `ja`, ipa: `[iś]`},{de: `du`, pl: `ty`, ipa: `[du]`},{de: `Sie`, pl: `pan/pani/państwo`, ipa: `[zi]`},{de: `Name`, pl: `imię, nazwisko`, ipa: `[na-me]`},{de: `Polen`, pl: `Polska`, ipa: `[po-len]`},{de: `Deutschland`, pl: `Niemcy`, ipa: `[dojcz-lant]`},{de: `kommen`, pl: `pochodzić, przychodzić`, ipa: `[ko-men]`},{de: `heißen`, pl: `nazywać się`, ipa: `[haj-sen]`},{de: `wohnen`, pl: `mieszkać`, ipa: `[wo-nen]`},{de: `Reisende`, pl: `osoba podróżująca`, ipa: `[raj-zen-de]`}], phrases: [{de: `Ich heiße Anna.`, pl: `Nazywam się Anna.`, ipa: `[iś haj-se an-na]`},{de: `Wie heißen Sie?`, pl: `Jak się pan/pani nazywa?`, ipa: `[wi haj-sen zi]`},{de: `Ich komme aus Polen.`, pl: `Pochodzę z Polski.`, ipa: `[iś ko-me ałs po-len]`},{de: `Ich wohne in Warschau.`, pl: `Mieszkam w Warszawie.`, ipa: `[iś wo-ne in war-szał]`},{de: `Freut mich.`, pl: `Miło mi.`, ipa: `[frojt miś]`},{de: `Ich bin Reisende.`, pl: `Jestem podróżniczką/podróżnikiem.`, ipa: `[iś bin raj-zen-de]`}], grammar: `„Ich heiße...” oznacza dosłownie „nazywam się...”. Do osoby obcej używaj formy „Sie”, która jest grzeczna i formalna. „Du” jest swobodne i pojawia się częściej wśród znajomych, studentów albo w luźnych miejscach.`, practice: [`Powiedz po niemiecku swoje imię.`,`Zapytaj formalnie kogoś o imię.`,`Powiedz, że pochodzisz z Polski.`,`Powiedz, że mieszkasz w swoim mieście.`,`Poćwicz krótką wymianę: powitanie, imię, „Freut mich”.`]},{day: 3, title: `Liczby i ceny`, title_native: `Zahlen und Preise`, focus: `W Hamburgu na targu, w piekarni i w automacie biletowym liczby są niezbędne. Nauczysz się rozumieć podstawowe ceny i ilości.`, vocab: [{de: `null`, pl: `zero`, ipa: `[nul]`},{de: `eins`, pl: `jeden`, ipa: `[ajns]`},{de: `zwei`, pl: `dwa`, ipa: `[cwaj]`},{de: `drei`, pl: `trzy`, ipa: `[draj]`},{de: `vier`, pl: `cztery`, ipa: `[fir]`},{de: `fünf`, pl: `pięć`, ipa: `[fynf]`},{de: `sechs`, pl: `sześć`, ipa: `[zeks]`},{de: `sieben`, pl: `siedem`, ipa: `[zi-ben]`},{de: `acht`, pl: `osiem`, ipa: `[aht]`},{de: `zehn`, pl: `dziesięć`, ipa: `[cejn]`}], phrases: [{de: `Wie viel kostet das?`, pl: `Ile to kosztuje?`, ipa: `[wi fil kos-tet das]`},{de: `Das kostet fünf Euro.`, pl: `To kosztuje pięć euro.`, ipa: `[das kos-tet fynf oj-ro]`},{de: `Ich nehme zwei.`, pl: `Wezmę dwa.`, ipa: `[iś nej-me cwaj]`},{de: `Nur eins, bitte.`, pl: `Tylko jedno, proszę.`, ipa: `[nur ajns, bi-te]`},{de: `Haben Sie Wechselgeld?`, pl: `Czy ma pan/pani drobne?`, ipa: `[ha-ben zi wek-sel-gelt]`},{de: `Das ist zu teuer.`, pl: `To jest za drogie.`, ipa: `[das ist cu toj-er]`}], grammar: `W pytaniu o cenę używa się „Wie viel kostet das?”, czyli „ile to kosztuje?”. „Euro” w codziennej mowie często nie zmienia formy po liczbach. Jeśli chcesz brzmieć uprzejmie, dodaj „bitte” na końcu zdania.`, practice: [`Zapytaj o cenę kawy.`,`Powiedz, że coś kosztuje pięć euro.`,`Zamów dwa precle.`,`Powiedz, że chcesz tylko jedną rzecz.`,`Zareaguj, gdy cena jest za wysoka.`]},{day: 4, title: `Podstawowe pytania`, title_native: `Grundlegende Fragen`, focus: `W Kolonii możesz potrzebować szybko zapytać o toaletę, stację albo wejście. Dziś poznasz najważniejsze słowa pytające.`, vocab: [{de: `wo`, pl: `gdzie`, ipa: `[wo]`},{de: `was`, pl: `co`, ipa: `[was]`},{de: `wer`, pl: `kto`, ipa: `[wer]`},{de: `wann`, pl: `kiedy`, ipa: `[wan]`},{de: `warum`, pl: `dlaczego`, ipa: `[wa-rum]`},{de: `wie`, pl: `jak`, ipa: `[wi]`},{de: `hier`, pl: `tutaj`, ipa: `[hir]`},{de: `dort`, pl: `tam`, ipa: `[dort]`},{de: `links`, pl: `w lewo`, ipa: `[links]`},{de: `rechts`, pl: `w prawo`, ipa: `[reśts]`}], phrases: [{de: `Wo ist die Toilette?`, pl: `Gdzie jest toaleta?`, ipa: `[wo ist di to-a-le-te]`},{de: `Was ist das?`, pl: `Co to jest?`, ipa: `[was ist das]`},{de: `Wann fährt der Zug?`, pl: `Kiedy odjeżdża pociąg?`, ipa: `[wan fert der cuk]`},{de: `Wie komme ich dorthin?`, pl: `Jak tam dotrę?`, ipa: `[wi ko-me iś dort-hin]`},{de: `Ist es hier?`, pl: `Czy to jest tutaj?`, ipa: `[ist es hir]`},{de: `Gehen Sie rechts.`, pl: `Proszę iść w prawo.`, ipa: `[ge-en zi reśts]`}], grammar: `W prostych pytaniach niemieckich czasownik często stoi na drugim miejscu po słowie pytającym: „Wo ist...?”, „Wann fährt...?”. Gdy pytanie nie ma słowa pytającego, czasownik idzie na początek: „Ist es hier?”. To bardzo praktyczny wzór w podróży.`, practice: [`Zapytaj, gdzie jest toaleta.`,`Zapytaj, kiedy odjeżdża pociąg.`,`Powiedz komuś, żeby poszedł w prawo.`,`Zapytaj, czy coś jest tutaj.`,`Ułóż pytanie z „was”.`]},{day: 5, title: `Uprzejmość i przeprosiny`, title_native: `Höflichkeit und Entschuldigung`, focus: `W Wiedniu formalna uprzejmość jest bardzo przydatna w kawiarniach i muzeach. Nauczysz się przepraszać, prosić o pomoc i reagować grzecznie.`, vocab: [{de: `Entschuldigung`, pl: `przepraszam`, ipa: `[ent-szul-di-gung]`},{de: `Verzeihung`, pl: `przepraszam, wybaczenie`, ipa: `[fer-caj-ung]`},{de: `Hilfe`, pl: `pomoc`, ipa: `[hil-fe]`},{de: `gern`, pl: `chętnie`, ipa: `[gern]`},{de: `kein Problem`, pl: `nie ma problemu`, ipa: `[kajn pro-blem]`},{de: `leider`, pl: `niestety`, ipa: `[laj-der]`},{de: `natürlich`, pl: `oczywiście`, ipa: `[na-tyr-liś]`},{de: `vielleicht`, pl: `może`, ipa: `[fi-lajśt]`},{de: `sofort`, pl: `natychmiast`, ipa: `[zo-fort]`},{de: `langsam`, pl: `powoli`, ipa: `[lang-zam]`}], phrases: [{de: `Entschuldigung, bitte.`, pl: `Przepraszam, proszę.`, ipa: `[ent-szul-di-gung, bi-te]`},{de: `Können Sie mir helfen?`, pl: `Czy może mi pan/pani pomóc?`, ipa: `[ky-nen zi mir hel-fen]`},{de: `Sprechen Sie bitte langsam.`, pl: `Proszę mówić powoli.`, ipa: `[szpre-śen zi bi-te lang-zam]`},{de: `Kein Problem.`, pl: `Nie ma problemu.`, ipa: `[kajn pro-blem]`},{de: `Leider nicht.`, pl: `Niestety nie.`, ipa: `[laj-der niśt]`},{de: `Natürlich, gern.`, pl: `Oczywiście, chętnie.`, ipa: `[na-tyr-liś, gern]`}], grammar: `„Können Sie...?” to bardzo użyteczna forma pytania „Czy może pan/pani...?”. Po niej czasownik główny zwykle trafia na koniec: „Können Sie mir helfen?”. W podróży ten schemat działa w dziesiątkach sytuacji.`, practice: [`Poproś nieznajomą osobę o pomoc.`,`Poproś, aby ktoś mówił wolniej.`,`Powiedz „niestety nie”.`,`Zareaguj „nie ma problemu”.`,`Ułóż pytanie zaczynające się od „Können Sie...”.`]},{day: 6, title: `W kawiarni`, title_native: `Im Café`, focus: `W Berlinie lub Wiedniu kawiarnia to idealne miejsce na pierwszą rozmowę po niemiecku. Nauczysz się zamawiać kawę, herbatę i coś słodkiego.`, vocab: [{de: `Kaffee`, pl: `kawa`, ipa: `[ka-fe]`},{de: `Tee`, pl: `herbata`, ipa: `[te]`},{de: `Wasser`, pl: `woda`, ipa: `[wa-ser]`},{de: `Milch`, pl: `mleko`, ipa: `[milś]`},{de: `Zucker`, pl: `cukier`, ipa: `[cu-ker]`},{de: `Kuchen`, pl: `ciasto`, ipa: `[ku-hen]`},{de: `Tasse`, pl: `filiżanka`, ipa: `[ta-se]`},{de: `Glas`, pl: `szklanka`, ipa: `[glas]`},{de: `heiß`, pl: `gorący`, ipa: `[hajs]`},{de: `kalt`, pl: `zimny`, ipa: `[kalt]`}], phrases: [{de: `Einen Kaffee, bitte.`, pl: `Kawę, proszę.`, ipa: `[aj-nen ka-fe, bi-te]`},{de: `Ich möchte einen Tee.`, pl: `Chciałbym/chciałabym herbatę.`, ipa: `[iś myś-te aj-nen te]`},{de: `Mit Milch, bitte.`, pl: `Z mlekiem, proszę.`, ipa: `[mit milś, bi-te]`},{de: `Ohne Zucker, bitte.`, pl: `Bez cukru, proszę.`, ipa: `[o-ne cu-ker, bi-te]`},{de: `Ein Glas Wasser, bitte.`, pl: `Szklankę wody, proszę.`, ipa: `[ajn glas wa-ser, bi-te]`},{de: `Zum Mitnehmen?`, pl: `Na wynos?`, ipa: `[cum mit-nej-men]`}], grammar: `„Ich möchte...” to uprzejme „chciałbym/chciałabym”. W kawiarni często wystarczy krótsza forma: „Einen Kaffee, bitte”. „Mit” znaczy „z”, a „ohne” znaczy „bez”.`, practice: [`Zamów kawę z mlekiem.`,`Zamów herbatę bez cukru.`,`Poproś o szklankę wody.`,`Odpowiedz, czy chcesz na wynos.`,`Zapytaj kolegę, czy chce kawę.`]},{day: 7, title: `Jedzenie i śniadanie`, title_native: `Essen und Frühstück`, focus: `W hotelu w Salzburgu albo w piekarni w Dreźnie warto znać słowa związane ze śniadaniem. Nauczysz się mówić, co chcesz zjeść.`, vocab: [{de: `Brot`, pl: `chleb`, ipa: `[brot]`},{de: `Brötchen`, pl: `bułka`, ipa: `[bryt-śen]`},{de: `Butter`, pl: `masło`, ipa: `[bu-ter]`},{de: `Käse`, pl: `ser`, ipa: `[ke-ze]`},{de: `Ei`, pl: `jajko`, ipa: `[aj]`},{de: `Marmelade`, pl: `dżem`, ipa: `[mar-me-la-de]`},{de: `Frühstück`, pl: `śniadanie`, ipa: `[fry-sztyk]`},{de: `Hunger`, pl: `głód`, ipa: `[hun-ger]`},{de: `lecker`, pl: `pyszny`, ipa: `[le-ker]`},{de: `Speisekarte`, pl: `karta dań`, ipa: `[szpaj-ze-kar-te]`}], phrases: [{de: `Ich habe Hunger.`, pl: `Jestem głodny/głodna.`, ipa: `[iś ha-be hun-ger]`},{de: `Was gibt es zum Frühstück?`, pl: `Co jest na śniadanie?`, ipa: `[was gibt es cum fry-sztyk]`},{de: `Ich nehme ein Brötchen.`, pl: `Wezmę bułkę.`, ipa: `[iś nej-me ajn bryt-śen]`},{de: `Das ist sehr lecker.`, pl: `To jest bardzo pyszne.`, ipa: `[das ist zejr le-ker]`},{de: `Haben Sie Käse?`, pl: `Czy ma pan/pani ser?`, ipa: `[ha-ben zi ke-ze]`},{de: `Die Speisekarte, bitte.`, pl: `Kartę dań, proszę.`, ipa: `[di szpaj-ze-kar-te, bi-te]`}], grammar: `„Ich habe Hunger” dosłownie znaczy „mam głód”, ale po polsku mówimy „jestem głodny”. W niemieckim wiele stanów wyraża się przez „haben”, czyli „mieć”. To dotyczy też pragnienia: „Ich habe Durst”.`, practice: [`Powiedz, że jesteś głodny.`,`Zapytaj, co jest na śniadanie.`,`Zamów bułkę i ser.`,`Powiedz, że jedzenie jest pyszne.`,`Poproś o kartę dań.`]},{day: 8, title: `W restauracji`, title_native: `Im Restaurant`, focus: `W Monachium w tradycyjnej restauracji możesz chcieć zamówić obiad i poprosić o rachunek. Dziś ćwiczysz najważniejsze zwroty kelnerskie.`, vocab: [{de: `Restaurant`, pl: `restauracja`, ipa: `[res-to-ran]`},{de: `Tisch`, pl: `stół`, ipa: `[tysz]`},{de: `Reservierung`, pl: `rezerwacja`, ipa: `[re-zer-wi-rung]`},{de: `Kellner`, pl: `kelner`, ipa: `[kel-ner]`},{de: `Rechnung`, pl: `rachunek`, ipa: `[reś-nung]`},{de: `Gericht`, pl: `danie`, ipa: `[ge-riśt]`},{de: `Fleisch`, pl: `mięso`, ipa: `[flajsz]`},{de: `Fisch`, pl: `ryba`, ipa: `[fisz]`},{de: `vegetarisch`, pl: `wegetariański`, ipa: `[we-ge-ta-risz]`},{de: `Empfehlung`, pl: `rekomendacja`, ipa: `[em-pfe-lung]`}], phrases: [{de: `Einen Tisch für zwei, bitte.`, pl: `Stolik dla dwóch osób, proszę.`, ipa: `[aj-nen tysz fyr cwaj, bi-te]`},{de: `Ich habe eine Reservierung.`, pl: `Mam rezerwację.`, ipa: `[iś ha-be aj-ne re-zer-wi-rung]`},{de: `Was empfehlen Sie?`, pl: `Co pan/pani poleca?`, ipa: `[was em-pfe-len zi]`},{de: `Ich esse vegetarisch.`, pl: `Jem wegetariańsko.`, ipa: `[iś e-se we-ge-ta-risz]`},{de: `Die Rechnung, bitte.`, pl: `Rachunek, proszę.`, ipa: `[di reś-nung, bi-te]`},{de: `Es war sehr gut.`, pl: `Było bardzo dobre.`, ipa: `[es war zejr gut]`}], grammar: `„Für zwei” oznacza „dla dwóch osób”. W restauracji często nie trzeba mówić pełnym zdaniem, ale uprzejme „bitte” zawsze pomaga. „Ich esse vegetarisch” jest prostym sposobem poinformowania o diecie.`, practice: [`Poproś o stolik dla dwóch osób.`,`Powiedz, że masz rezerwację.`,`Zapytaj kelnera o rekomendację.`,`Powiedz, że jesz wegetariańsko.`,`Poproś o rachunek.`]},{day: 9, title: `Zakupy spożywcze`, title_native: `Lebensmittel einkaufen`, focus: `W supermarkecie w Frankfurcie musisz rozumieć produkty, ilości i proste pytania przy kasie. Nauczysz się kupować podstawowe artykuły.`, vocab: [{de: `Supermarkt`, pl: `supermarket`, ipa: `[zu-per-markt]`},{de: `Bäckerei`, pl: `piekarnia`, ipa: `[be-ke-raj]`},{de: `Obst`, pl: `owoce`, ipa: `[opst]`},{de: `Gemüse`, pl: `warzywa`, ipa: `[ge-my-ze]`},{de: `Apfel`, pl: `jabłko`, ipa: `[ap-fel]`},{de: `Banane`, pl: `banan`, ipa: `[ba-na-ne]`},{de: `Käse`, pl: `ser`, ipa: `[ke-ze]`},{de: `Flasche`, pl: `butelka`, ipa: `[fla-sze]`},{de: `Tüte`, pl: `torba`, ipa: `[ty-te]`},{de: `Kasse`, pl: `kasa`, ipa: `[ka-se]`}], phrases: [{de: `Ich suche Äpfel.`, pl: `Szukam jabłek.`, ipa: `[iś zu-he ep-fel]`},{de: `Wo ist die Kasse?`, pl: `Gdzie jest kasa?`, ipa: `[wo ist di ka-se]`},{de: `Eine Flasche Wasser, bitte.`, pl: `Butelkę wody, proszę.`, ipa: `[aj-ne fla-sze wa-ser, bi-te]`},{de: `Brauchen Sie eine Tüte?`, pl: `Czy potrzebuje pan/pani torby?`, ipa: `[brał-hen zi aj-ne ty-te]`},{de: `Nein, ich habe eine Tasche.`, pl: `Nie, mam torbę.`, ipa: `[najn, iś ha-be aj-ne ta-sze]`},{de: `Kann ich mit Karte zahlen?`, pl: `Czy mogę zapłacić kartą?`, ipa: `[kan iś mit kar-te ca-len]`}], grammar: `„Ich suche...” znaczy „szukam...”. W sklepie to bardzo przydatna konstrukcja, gdy nie wiesz, gdzie coś leży. „Mit Karte zahlen” oznacza „płacić kartą”, a „bar zahlen” oznacza „płacić gotówką”.`, practice: [`Powiedz, że szukasz owoców.`,`Zapytaj, gdzie jest kasa.`,`Poproś o butelkę wody.`,`Odmów torby przy kasie.`,`Zapytaj, czy możesz zapłacić kartą.`]},{day: 10, title: `Transport miejski`, title_native: `Öffentliche Verkehrsmittel`, focus: `W Berlinie, Wiedniu i Zurychu transport publiczny działa sprawnie, ale wymaga znajomości podstawowych słów. Nauczysz się mówić o metrze, tramwaju i autobusie.`, vocab: [{de: `Bahnhof`, pl: `dworzec`, ipa: `[ban-hof]`},{de: `Haltestelle`, pl: `przystanek`, ipa: `[hal-te-szte-le]`},{de: `U-Bahn`, pl: `metro`, ipa: `[u-ban]`},{de: `S-Bahn`, pl: `kolej miejska`, ipa: `[es-ban]`},{de: `Straßenbahn`, pl: `tramwaj`, ipa: `[sztra-sen-ban]`},{de: `Bus`, pl: `autobus`, ipa: `[bus]`},{de: `Ticket`, pl: `bilet`, ipa: `[ti-ket]`},{de: `Linie`, pl: `linia`, ipa: `[li-ni-e]`},{de: `Richtung`, pl: `kierunek`, ipa: `[riś-tung]`},{de: `Fahrplan`, pl: `rozkład jazdy`, ipa: `[far-plan]`}], phrases: [{de: `Wo ist die nächste Haltestelle?`, pl: `Gdzie jest najbliższy przystanek?`, ipa: `[wo ist di nek-ste hal-te-szte-le]`},{de: `Ich brauche ein Ticket.`, pl: `Potrzebuję biletu.`, ipa: `[iś brał-he ajn ti-ket]`},{de: `Welche Linie fährt zum Zentrum?`, pl: `Która linia jedzie do centrum?`, ipa: `[wel-he li-ni-e fert cum cen-trum]`},{de: `In welche Richtung?`, pl: `W którym kierunku?`, ipa: `[in wel-he riś-tung]`},{de: `Der Bus kommt gleich.`, pl: `Autobus zaraz przyjedzie.`, ipa: `[der bus komt glajś]`},{de: `Ist das die U-Bahn?`, pl: `Czy to jest metro?`, ipa: `[ist das di u-ban]`}], grammar: `„Welche” oznacza „która” lub „jaka” i przydaje się przy wyborze linii, biletu albo peronu. „Zum Zentrum” znaczy „do centrum”. W miastach niemieckojęzycznych nazwy kierunków często widnieją na tablicach zamiast nazw dzielnic, więc warto pytać o „Richtung”.`, practice: [`Zapytaj o najbliższy przystanek.`,`Powiedz, że potrzebujesz biletu.`,`Zapytaj, która linia jedzie do centrum.`,`Zapytaj o kierunek.`,`Powiedz, że autobus zaraz przyjedzie.`]},{day: 11, title: `Na dworcu kolejowym`, title_native: `Am Bahnhof`, focus: `Podróżując z Berlina do Hamburga albo z Wiednia do Salzburga, musisz rozumieć perony i godziny odjazdu. Dziś ćwiczysz język kolei.`, vocab: [{de: `Zug`, pl: `pociąg`, ipa: `[cuk]`},{de: `Gleis`, pl: `peron, tor`, ipa: `[glajs]`},{de: `Abfahrt`, pl: `odjazd`, ipa: `[ap-fart]`},{de: `Ankunft`, pl: `przyjazd`, ipa: `[an-kunft]`},{de: `Verspätung`, pl: `opóźnienie`, ipa: `[fer-szpe-tung]`},{de: `Fahrkarte`, pl: `bilet kolejowy`, ipa: `[far-kar-te]`},{de: `Sitzplatz`, pl: `miejsce siedzące`, ipa: `[zyc-plac]`},{de: `Wagen`, pl: `wagon`, ipa: `[wa-gen]`},{de: `umsteigen`, pl: `przesiadać się`, ipa: `[um-sztaj-gen]`},{de: `direkt`, pl: `bezpośredni`, ipa: `[di-rekt]`}], phrases: [{de: `Von welchem Gleis fährt der Zug?`, pl: `Z którego peronu odjeżdża pociąg?`, ipa: `[fon wel-hem glajs fert der cuk]`},{de: `Der Zug hat Verspätung.`, pl: `Pociąg ma opóźnienie.`, ipa: `[der cuk hat fer-szpe-tung]`},{de: `Muss ich umsteigen?`, pl: `Czy muszę się przesiadać?`, ipa: `[mus iś um-sztaj-gen]`},{de: `Ich habe eine Fahrkarte.`, pl: `Mam bilet kolejowy.`, ipa: `[iś ha-be aj-ne far-kar-te]`},{de: `Ist dieser Sitzplatz frei?`, pl: `Czy to miejsce jest wolne?`, ipa: `[ist di-zer zyc-plac fraj]`},{de: `Der Zug fährt direkt.`, pl: `Pociąg jedzie bezpośrednio.`, ipa: `[der cuk fert di-rekt]`}], grammar: `„Muss ich...?” oznacza „czy muszę...?”. Po czasowniku modalnym „muss” drugi czasownik idzie na koniec: „Muss ich umsteigen?”. Ten wzór pomoże pytać o obowiązek lub konieczność.`, practice: [`Zapytaj, z którego peronu odjeżdża pociąg.`,`Powiedz, że pociąg ma opóźnienie.`,`Zapytaj, czy musisz się przesiadać.`,`Sprawdź, czy miejsce jest wolne.`,`Powiedz, że masz bilet kolejowy.`]},{day: 12, title: `Taksówka i przejazd`, title_native: `Taxi und Fahrt`, focus: `Po przylocie do Zurychu albo Wiednia możesz potrzebować taksówki. Nauczysz się podawać adres, pytać o cenę i mówić o czasie przejazdu.`, vocab: [{de: `Taxi`, pl: `taksówka`, ipa: `[tak-si]`},{de: `Adresse`, pl: `adres`, ipa: `[a-dre-se]`},{de: `Hotel`, pl: `hotel`, ipa: `[ho-tel]`},{de: `Flughafen`, pl: `lotnisko`, ipa: `[fluk-ha-fen]`},{de: `Zentrum`, pl: `centrum`, ipa: `[cen-trum]`},{de: `schnell`, pl: `szybko`, ipa: `[sznel]`},{de: `lang`, pl: `długo`, ipa: `[lang]`},{de: `Minuten`, pl: `minuty`, ipa: `[mi-nu-ten]`},{de: `links`, pl: `w lewo`, ipa: `[links]`},{de: `geradeaus`, pl: `prosto`, ipa: `[ge-ra-de-ałs]`}], phrases: [{de: `Zum Hotel, bitte.`, pl: `Do hotelu, proszę.`, ipa: `[cum ho-tel, bi-te]`},{de: `Hier ist die Adresse.`, pl: `Oto adres.`, ipa: `[hir ist di a-dre-se]`},{de: `Wie lange dauert die Fahrt?`, pl: `Ile potrwa przejazd?`, ipa: `[wi lan-ge dał-ert di fart]`},{de: `Fahren Sie bitte geradeaus.`, pl: `Proszę jechać prosto.`, ipa: `[fa-ren zi bi-te ge-ra-de-ałs]`},{de: `Können Sie hier halten?`, pl: `Czy może pan/pani tutaj się zatrzymać?`, ipa: `[ky-nen zi hir hal-ten]`},{de: `Was kostet die Fahrt?`, pl: `Ile kosztuje przejazd?`, ipa: `[was kos-tet di fart]`}], grammar: `„Zum” to skrócona forma od „zu dem” i oznacza „do” w rodzaju męskim lub nijakim, np. „zum Hotel”. W taksówce warto mówić krótko i jasno: adres, kierunek, pytanie o cenę. „Hier” oznacza „tutaj” i jest bardzo praktyczne przy wysiadaniu.`, practice: [`Poproś taksówkarza o przejazd do hotelu.`,`Pokaż adres po niemiecku.`,`Zapytaj, ile potrwa przejazd.`,`Poproś, żeby kierowca zatrzymał się tutaj.`,`Zapytaj o koszt przejazdu.`]},{day: 13, title: `Hotel i meldowanie`, title_native: `Hotel und Einchecken`, focus: `W hotelu w Salzburgu, Berlinie albo Kolonii potrzebujesz kilku konkretnych zwrotów. Nauczysz się meldować, pytać o pokój i śniadanie.`, vocab: [{de: `Rezeption`, pl: `recepcja`, ipa: `[re-cep-cjon]`},{de: `Zimmer`, pl: `pokój`, ipa: `[cy-mer]`},{de: `Schlüssel`, pl: `klucz`, ipa: `[szly-sel]`},{de: `Pass`, pl: `paszport`, ipa: `[pas]`},{de: `Reservierung`, pl: `rezerwacja`, ipa: `[re-zer-wi-rung]`},{de: `Nacht`, pl: `noc`, ipa: `[naht]`},{de: `Frühstück`, pl: `śniadanie`, ipa: `[fry-sztyk]`},{de: `Aufzug`, pl: `winda`, ipa: `[ałf-cuk]`},{de: `Etage`, pl: `piętro`, ipa: `[e-ta-że]`},{de: `WLAN`, pl: `Wi-Fi`, ipa: `[we-lan]`}], phrases: [{de: `Ich möchte einchecken.`, pl: `Chciałbym/chciałabym się zameldować.`, ipa: `[iś myś-te ajn-cze-ken]`},{de: `Ich habe eine Reservierung.`, pl: `Mam rezerwację.`, ipa: `[iś ha-be aj-ne re-zer-wi-rung]`},{de: `Hier ist mein Pass.`, pl: `Oto mój paszport.`, ipa: `[hir ist majn pas]`},{de: `Wo ist mein Zimmer?`, pl: `Gdzie jest mój pokój?`, ipa: `[wo ist majn cy-mer]`},{de: `Ist Frühstück inklusive?`, pl: `Czy śniadanie jest w cenie?`, ipa: `[ist fry-sztyk in-klu-zi-ve]`},{de: `Wie ist das WLAN-Passwort?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `[wi ist das we-lan pas-wort]`}], grammar: `„Mein” oznacza „mój” i zmienia się zależnie od rzeczownika, ale w podróży możesz zapamiętać całe frazy: „mein Zimmer”, „mein Pass”. „Ich möchte einchecken” jest zrozumiałe i naturalne w hotelach. Angielskie słowo „einchecken” funkcjonuje w niemieckiej obsłudze turystycznej.`, practice: [`Powiedz, że chcesz się zameldować.`,`Powiedz, że masz rezerwację.`,`Zapytaj o swój pokój.`,`Zapytaj, czy śniadanie jest w cenie.`,`Zapytaj o hasło do Wi-Fi.`]},{day: 14, title: `Problemy w hotelu`, title_native: `Probleme im Hotel`, focus: `Jeśli w pokoju w Dreźnie nie działa ogrzewanie albo Wi-Fi, trzeba umieć zgłosić problem. Dziś nauczysz się prostych reklamacji.`, vocab: [{de: `Problem`, pl: `problem`, ipa: `[pro-blem]`},{de: `kaputt`, pl: `zepsuty`, ipa: `[ka-put]`},{de: `laut`, pl: `głośny`, ipa: `[lałt]`},{de: `leise`, pl: `cichy`, ipa: `[laj-ze]`},{de: `sauber`, pl: `czysty`, ipa: `[zał-ber]`},{de: `schmutzig`, pl: `brudny`, ipa: `[szmuc-iś]`},{de: `Heizung`, pl: `ogrzewanie`, ipa: `[haj-cung]`},{de: `Klimaanlage`, pl: `klimatyzacja`, ipa: `[kli-ma-an-la-ge]`},{de: `Handtuch`, pl: `ręcznik`, ipa: `[hant-tuś]`},{de: `wechseln`, pl: `zmienić, wymienić`, ipa: `[wek-seln]`}], phrases: [{de: `Die Heizung ist kaputt.`, pl: `Ogrzewanie jest zepsute.`, ipa: `[di haj-cung ist ka-put]`},{de: `Das Zimmer ist zu laut.`, pl: `Pokój jest za głośny.`, ipa: `[das cy-mer ist cu lałt]`},{de: `Ich brauche ein neues Handtuch.`, pl: `Potrzebuję nowego ręcznika.`, ipa: `[iś brał-he ajn noj-es hant-tuś]`},{de: `Können Sie das bitte prüfen?`, pl: `Czy może pan/pani to sprawdzić?`, ipa: `[ky-nen zi das bi-te pry-fen]`},{de: `Das WLAN funktioniert nicht.`, pl: `Wi-Fi nie działa.`, ipa: `[das we-lan funk-cjo-nirt niśt]`},{de: `Kann ich das Zimmer wechseln?`, pl: `Czy mogę zmienić pokój?`, ipa: `[kan iś das cy-mer wek-seln]`}], grammar: `„Nicht” zaprzecza czasownik lub całe zdanie: „funktioniert nicht”. „Kein” zaprzecza rzeczownik, np. „kein Handtuch” — „żaden ręcznik”. W zgłoszeniach hotelowych najlepiej mówić spokojnie i konkretnie, zaczynając od problemu.`, practice: [`Powiedz, że Wi-Fi nie działa.`,`Zgłoś, że ogrzewanie jest zepsute.`,`Poproś o nowy ręcznik.`,`Zapytaj, czy możesz zmienić pokój.`,`Poproś obsługę o sprawdzenie problemu.`]},{day: 15, title: `Kierunki w mieście`, title_native: `Richtungen in der Stadt`, focus: `Spacerując po Pradze niemieckojęzyczną grupą albo po Wiedniu, możesz pytać o drogę. Dziś uczysz się kierunków i punktów orientacyjnych.`, vocab: [{de: `Straße`, pl: `ulica`, ipa: `[sztra-se]`},{de: `Platz`, pl: `plac`, ipa: `[plac]`},{de: `Brücke`, pl: `most`, ipa: `[bry-ke]`},{de: `Ecke`, pl: `róg`, ipa: `[e-ke]`},{de: `Nähe`, pl: `bliskość`, ipa: `[ne-e]`},{de: `weit`, pl: `daleko`, ipa: `[wajt]`},{de: `geradeaus`, pl: `prosto`, ipa: `[ge-ra-de-ałs]`},{de: `zurück`, pl: `z powrotem`, ipa: `[cu-ryk]`},{de: `Karte`, pl: `mapa`, ipa: `[kar-te]`},{de: `Altstadt`, pl: `stare miasto`, ipa: `[alt-sztat]`}], phrases: [{de: `Wo ist die Altstadt?`, pl: `Gdzie jest stare miasto?`, ipa: `[wo ist di alt-sztat]`},{de: `Gehen Sie geradeaus.`, pl: `Proszę iść prosto.`, ipa: `[ge-en zi ge-ra-de-ałs]`},{de: `Dann links.`, pl: `Potem w lewo.`, ipa: `[dan links]`},{de: `Es ist an der Ecke.`, pl: `To jest na rogu.`, ipa: `[es ist an der e-ke]`},{de: `Ist es weit von hier?`, pl: `Czy to daleko stąd?`, ipa: `[ist es wajt fon hir]`},{de: `Ich brauche eine Karte.`, pl: `Potrzebuję mapy.`, ipa: `[iś brał-he aj-ne kar-te]`}], grammar: `„Von hier” oznacza „stąd”. Przy kierunkach możesz używać krótkich zdań: „geradeaus”, „dann links”, „an der Ecke”. W rozmowie na ulicy krótkie odpowiedzi są naturalne i łatwiejsze do zrozumienia.`, practice: [`Zapytaj, gdzie jest stare miasto.`,`Powiedz komuś: prosto, potem w lewo.`,`Zapytaj, czy to daleko stąd.`,`Powiedz, że miejsce jest na rogu.`,`Poproś o mapę.`]},{day: 16, title: `Zwiedzanie i bilety`, title_native: `Besichtigung und Eintrittskarten`, focus: `W muzeach Berlina, Wiednia i Monachium trzeba kupić bilety i pytać o godziny otwarcia. Dziś ćwiczysz język zwiedzania.`, vocab: [{de: `Museum`, pl: `muzeum`, ipa: `[mu-ze-um]`},{de: `Schloss`, pl: `zamek, pałac`, ipa: `[szlos]`},{de: `Kirche`, pl: `kościół`, ipa: `[kir-śe]`},{de: `Eintritt`, pl: `wstęp`, ipa: `[ajn-trit]`},{de: `Ticket`, pl: `bilet`, ipa: `[ti-ket]`},{de: `Öffnungszeiten`, pl: `godziny otwarcia`, ipa: `[yf-nungs-caj-ten]`},{de: `Führung`, pl: `oprowadzanie`, ipa: `[fy-rung]`},{de: `Ausstellung`, pl: `wystawa`, ipa: `[ałs-szte-lung]`},{de: `Foto`, pl: `zdjęcie`, ipa: `[fo-to]`},{de: `erlaubt`, pl: `dozwolony`, ipa: `[er-lałpt]`}], phrases: [{de: `Wann öffnet das Museum?`, pl: `Kiedy muzeum się otwiera?`, ipa: `[wan yf-net das mu-ze-um]`},{de: `Wie viel kostet der Eintritt?`, pl: `Ile kosztuje wstęp?`, ipa: `[wi fil kos-tet der ajn-trit]`},{de: `Gibt es eine Führung?`, pl: `Czy jest oprowadzanie?`, ipa: `[gibt es aj-ne fy-rung]`},{de: `Darf ich Fotos machen?`, pl: `Czy mogę robić zdjęcia?`, ipa: `[darf iś fo-tos ma-hen]`},{de: `Ein Ticket für Erwachsene, bitte.`, pl: `Jeden bilet dla dorosłych, proszę.`, ipa: `[ajn ti-ket fyr er-wak-se-ne, bi-te]`},{de: `Die Ausstellung ist interessant.`, pl: `Wystawa jest interesująca.`, ipa: `[di ałs-szte-lung ist in-te-re-sant]`}], grammar: `„Darf ich...?” oznacza „czy wolno mi...?” i używa się go przy pozwoleniach. „Darf ich Fotos machen?” jest idealne w muzeum, galerii albo kościele. To bardziej odpowiednie niż samo „Kann ich”, bo pytasz o zgodę.`, practice: [`Zapytaj o godziny otwarcia muzeum.`,`Zapytaj, ile kosztuje wstęp.`,`Poproś o bilet dla dorosłej osoby.`,`Zapytaj, czy wolno robić zdjęcia.`,`Zapytaj, czy jest oprowadzanie.`]},{day: 17, title: `Pogoda i ubrania`, title_native: `Wetter und Kleidung`, focus: `W Alpach, Hamburgu czy Berlinie pogoda może się szybko zmieniać. Nauczysz się mówić o deszczu, zimnie i ubraniach.`, vocab: [{de: `Wetter`, pl: `pogoda`, ipa: `[we-ter]`},{de: `Sonne`, pl: `słońce`, ipa: `[zo-ne]`},{de: `Regen`, pl: `deszcz`, ipa: `[re-gen]`},{de: `Schnee`, pl: `śnieg`, ipa: `[szne]`},{de: `Wind`, pl: `wiatr`, ipa: `[wint]`},{de: `warm`, pl: `ciepły`, ipa: `[warm]`},{de: `kalt`, pl: `zimny`, ipa: `[kalt]`},{de: `Jacke`, pl: `kurtka`, ipa: `[ja-ke]`},{de: `Schuhe`, pl: `buty`, ipa: `[szu-e]`},{de: `Regenschirm`, pl: `parasol`, ipa: `[re-gen-szirm]`}], phrases: [{de: `Wie ist das Wetter?`, pl: `Jaka jest pogoda?`, ipa: `[wi ist das we-ter]`},{de: `Es regnet.`, pl: `Pada deszcz.`, ipa: `[es reg-net]`},{de: `Es ist kalt heute.`, pl: `Dziś jest zimno.`, ipa: `[es ist kalt hoj-te]`},{de: `Ich brauche eine Jacke.`, pl: `Potrzebuję kurtki.`, ipa: `[iś brał-he aj-ne ja-ke]`},{de: `Haben Sie einen Regenschirm?`, pl: `Czy ma pan/pani parasol?`, ipa: `[ha-ben zi aj-nen re-gen-szirm]`},{de: `Morgen wird es warm.`, pl: `Jutro będzie ciepło.`, ipa: `[mor-gen wirt es warm]`}], grammar: `W niemieckim przy pogodzie często używa się bezosobowego „es”: „Es regnet”, „Es ist kalt”. Nie tłumacz tego dosłownie jako „ono”. To po prostu naturalny sposób mówienia o pogodzie.`, practice: [`Zapytaj o pogodę.`,`Powiedz, że pada deszcz.`,`Powiedz, że dziś jest zimno.`,`Powiedz, że potrzebujesz kurtki.`,`Zapytaj w sklepie o parasol.`]},{day: 18, title: `Zakupy odzieżowe`, title_native: `Kleidung einkaufen`, focus: `W centrum handlowym w Düsseldorfie albo na ulicy handlowej w Wiedniu możesz kupować ubrania. Nauczysz się pytać o rozmiar, kolor i przymierzalnię.`, vocab: [{de: `Kleidung`, pl: `ubrania`, ipa: `[klaj-dung]`},{de: `Hemd`, pl: `koszula`, ipa: `[hemt]`},{de: `Hose`, pl: `spodnie`, ipa: `[ho-ze]`},{de: `Kleid`, pl: `sukienka`, ipa: `[klajt]`},{de: `Schuhe`, pl: `buty`, ipa: `[szu-e]`},{de: `Größe`, pl: `rozmiar`, ipa: `[gry-se]`},{de: `Farbe`, pl: `kolor`, ipa: `[far-be]`},{de: `schwarz`, pl: `czarny`, ipa: `[szwarc]`},{de: `weiß`, pl: `biały`, ipa: `[wajs]`},{de: `Umkleidekabine`, pl: `przymierzalnia`, ipa: `[um-klaj-de-ka-bi-ne]`}], phrases: [{de: `Haben Sie diese Größe?`, pl: `Czy ma pan/pani ten rozmiar?`, ipa: `[ha-ben zi di-ze gry-se]`},{de: `Ich suche eine schwarze Hose.`, pl: `Szukam czarnych spodni.`, ipa: `[iś zu-he aj-ne szwar-ce ho-ze]`},{de: `Wo ist die Umkleidekabine?`, pl: `Gdzie jest przymierzalnia?`, ipa: `[wo ist di um-klaj-de-ka-bi-ne]`},{de: `Das passt gut.`, pl: `To dobrze pasuje.`, ipa: `[das past gut]`},{de: `Das ist zu klein.`, pl: `To jest za małe.`, ipa: `[das ist cu klajn]`},{de: `Ich nehme es.`, pl: `Wezmę to.`, ipa: `[iś nej-me es]`}], grammar: `„Zu” przed przymiotnikiem oznacza „za”: „zu klein”, „zu teuer”, „zu laut”. To świetne słowo w zakupach i hotelu. „Das passt” oznacza, że coś pasuje rozmiarem lub stylem.`, practice: [`Zapytaj o konkretny rozmiar.`,`Powiedz, że szukasz czarnych spodni.`,`Zapytaj o przymierzalnię.`,`Powiedz, że coś jest za małe.`,`Powiedz, że bierzesz daną rzecz.`]},{day: 19, title: `Apteka i zdrowie`, title_native: `Apotheke und Gesundheit`, focus: `W aptece w Monachium albo Zurychu trzeba jasno opisać objawy. Nauczysz się mówić o bólu, lekach i prostych potrzebach zdrowotnych.`, vocab: [{de: `Apotheke`, pl: `apteka`, ipa: `[a-po-te-ke]`},{de: `Medikament`, pl: `lek`, ipa: `[me-di-ka-ment]`},{de: `Schmerz`, pl: `ból`, ipa: `[szmerc]`},{de: `Kopfschmerzen`, pl: `ból głowy`, ipa: `[kopf-szmer-cen]`},{de: `Bauchschmerzen`, pl: `ból brzucha`, ipa: `[bałch-szmer-cen]`},{de: `Husten`, pl: `kaszel`, ipa: `[hu-sten]`},{de: `Fieber`, pl: `gorączka`, ipa: `[fi-ber]`},{de: `Allergie`, pl: `alergia`, ipa: `[a-ler-gi]`},{de: `Pflaster`, pl: `plaster`, ipa: `[pfla-ster]`},{de: `Arzt`, pl: `lekarz`, ipa: `[arct]`}], phrases: [{de: `Ich habe Kopfschmerzen.`, pl: `Boli mnie głowa.`, ipa: `[iś ha-be kopf-szmer-cen]`},{de: `Ich brauche ein Medikament.`, pl: `Potrzebuję leku.`, ipa: `[iś brał-he ajn me-di-ka-ment]`},{de: `Haben Sie etwas gegen Husten?`, pl: `Czy ma pan/pani coś na kaszel?`, ipa: `[ha-ben zi et-was ge-gen hu-sten]`},{de: `Ich habe eine Allergie.`, pl: `Mam alergię.`, ipa: `[iś ha-be aj-ne a-ler-gi]`},{de: `Wo ist der nächste Arzt?`, pl: `Gdzie jest najbliższy lekarz?`, ipa: `[wo ist der nek-ste arct]`},{de: `Ist das rezeptfrei?`, pl: `Czy to jest bez recepty?`, ipa: `[ist das re-cept-fraj]`}], grammar: `„Gegen” w aptece znaczy „na” w sensie „przeciwko”: „etwas gegen Husten” to „coś na kaszel”. Przy dolegliwościach Niemcy często mówią „Ich habe...” i rzeczownik w liczbie mnogiej, np. „Kopfschmerzen”.`, practice: [`Powiedz, że boli cię głowa.`,`Zapytaj o coś na kaszel.`,`Powiedz, że masz alergię.`,`Zapytaj, czy lek jest bez recepty.`,`Zapytaj o najbliższego lekarza.`]},{day: 20, title: `Nagłe sytuacje`, title_native: `Notfälle`, focus: `W podróży trzeba znać język bezpieczeństwa. Nauczysz się prosić o pomoc, dzwonić po służby i zgłaszać zgubione rzeczy.`, vocab: [{de: `Notfall`, pl: `nagły wypadek`, ipa: `[not-fal]`},{de: `Polizei`, pl: `policja`, ipa: `[po-li-caj]`},{de: `Krankenwagen`, pl: `karetka`, ipa: `[kran-ken-wa-gen]`},{de: `Feuerwehr`, pl: `straż pożarna`, ipa: `[foj-er-wer]`},{de: `Hilfe`, pl: `pomoc`, ipa: `[hil-fe]`},{de: `verloren`, pl: `zgubiony`, ipa: `[fer-lo-ren]`},{de: `gestohlen`, pl: `skradziony`, ipa: `[ge-szto-len]`},{de: `Pass`, pl: `paszport`, ipa: `[pas]`},{de: `Handy`, pl: `telefon komórkowy`, ipa: `[hen-di]`},{de: `gefährlich`, pl: `niebezpieczny`, ipa: `[ge-fer-liś]`}], phrases: [{de: `Hilfe, bitte!`, pl: `Pomocy, proszę!`, ipa: `[hil-fe, bi-te]`},{de: `Rufen Sie die Polizei!`, pl: `Proszę wezwać policję!`, ipa: `[ru-fen zi di po-li-caj]`},{de: `Ich habe meinen Pass verloren.`, pl: `Zgubiłem/zgubiłam paszport.`, ipa: `[iś ha-be maj-nen pas fer-lo-ren]`},{de: `Mein Handy wurde gestohlen.`, pl: `Mój telefon został skradziony.`, ipa: `[majn hen-di wur-de ge-szto-len]`},{de: `Ich brauche einen Krankenwagen.`, pl: `Potrzebuję karetki.`, ipa: `[iś brał-he aj-nen kran-ken-wa-gen]`},{de: `Das ist gefährlich.`, pl: `To jest niebezpieczne.`, ipa: `[das ist ge-fer-liś]`}], grammar: `W nagłych sytuacjach krótkie zdania są najlepsze. Tryb rozkazujący formalny często wygląda jak czasownik plus „Sie”: „Rufen Sie...”. Możesz też używać prostego „Ich brauche...” do natychmiastowej potrzeby.`, practice: [`Poproś o pomoc.`,`Poproś kogoś o wezwanie policji.`,`Powiedz, że zgubiłeś paszport.`,`Powiedz, że telefon został skradziony.`,`Powiedz, że potrzebujesz karetki.`]},{day: 21, title: `Czas i umawianie się`, title_native: `Zeit und Verabredungen`, focus: `Umawiając się z przewodnikiem w Berlinie albo znajomym w Wiedniu, potrzebujesz godzin i dni. Dziś ćwiczysz czas w praktyce.`, vocab: [{de: `Uhr`, pl: `godzina`, ipa: `[ur]`},{de: `Minute`, pl: `minuta`, ipa: `[mi-nu-te]`},{de: `heute`, pl: `dziś`, ipa: `[hoj-te]`},{de: `morgen`, pl: `jutro`, ipa: `[mor-gen]`},{de: `gestern`, pl: `wczoraj`, ipa: `[ges-tern]`},{de: `Montag`, pl: `poniedziałek`, ipa: `[mon-tak]`},{de: `Freitag`, pl: `piątek`, ipa: `[fraj-tak]`},{de: `Wochenende`, pl: `weekend`, ipa: `[wo-hen-en-de]`},{de: `spät`, pl: `późno`, ipa: `[szpejt]`},{de: `früh`, pl: `wcześnie`, ipa: `[fry]`}], phrases: [{de: `Wie spät ist es?`, pl: `Która jest godzina?`, ipa: `[wi szpejt ist es]`},{de: `Es ist zehn Uhr.`, pl: `Jest dziesiąta.`, ipa: `[es ist cejn ur]`},{de: `Heute habe ich Zeit.`, pl: `Dziś mam czas.`, ipa: `[hoj-te ha-be iś cajt]`},{de: `Morgen passt gut.`, pl: `Jutro pasuje.`, ipa: `[mor-gen past gut]`},{de: `Treffen wir uns um acht?`, pl: `Spotkamy się o ósmej?`, ipa: `[tre-fen wir uns um aht]`},{de: `Ich komme später.`, pl: `Przyjdę później.`, ipa: `[iś ko-me szpe-ter]`}], grammar: `Godziny podaje się z „um”: „um acht” — „o ósmej”. „Es ist zehn Uhr” to pełna, prosta forma godziny. „Passt gut” to naturalny zwrot oznaczający „pasuje dobrze”.`, practice: [`Zapytaj, która jest godzina.`,`Powiedz, że jest dziesiąta.`,`Zaproponuj spotkanie o ósmej.`,`Powiedz, że jutro pasuje.`,`Powiedz, że przyjdziesz później.`]},{day: 22, title: `Rozmowy towarzyskie`, title_native: `Small Talk`, focus: `W hostelu, barze albo podczas wycieczki po Hamburgu przyda się small talk. Nauczysz się mówić o podróży, zainteresowaniach i samopoczuciu.`, vocab: [{de: `Reise`, pl: `podróż`, ipa: `[raj-ze]`},{de: `Urlaub`, pl: `urlop, wakacje`, ipa: `[ur-lałp]`},{de: `Stadt`, pl: `miasto`, ipa: `[sztat]`},{de: `schön`, pl: `piękny, ładny`, ipa: `[szyn]`},{de: `interessant`, pl: `interesujący`, ipa: `[in-te-re-sant]`},{de: `nett`, pl: `miły`, ipa: `[net]`},{de: `müde`, pl: `zmęczony`, ipa: `[my-de]`},{de: `gut`, pl: `dobrze, dobry`, ipa: `[gut]`},{de: `Musik`, pl: `muzyka`, ipa: `[mu-zik]`},{de: `Film`, pl: `film`, ipa: `[film]`}], phrases: [{de: `Wie geht es Ihnen?`, pl: `Jak się pan/pani ma?`, ipa: `[wi gejt es i-nen]`},{de: `Mir geht es gut.`, pl: `Mam się dobrze.`, ipa: `[mir gejt es gut]`},{de: `Die Stadt ist schön.`, pl: `Miasto jest piękne.`, ipa: `[di sztat ist szyn]`},{de: `Ich bin im Urlaub.`, pl: `Jestem na wakacjach.`, ipa: `[iś bin im ur-lałp]`},{de: `Ich mag Musik.`, pl: `Lubię muzykę.`, ipa: `[iś mak mu-zik]`},{de: `Es war nett, Sie kennenzulernen.`, pl: `Miło było pana/panią poznać.`, ipa: `[es war net, zi ke-nen-cu-ler-nen]`}], grammar: `„Wie geht es Ihnen?” jest formalne, a „Wie geht’s?” swobodne. Odpowiedź „Mir geht es gut” dosłownie znaczy „mi idzie dobrze”, ale po polsku to „mam się dobrze”. „Ich mag...” to prosty sposób mówienia o tym, co lubisz.`, practice: [`Zapytaj formalnie o samopoczucie.`,`Powiedz, że masz się dobrze.`,`Powiedz, że miasto jest piękne.`,`Powiedz, że jesteś na wakacjach.`,`Powiedz, że lubisz muzykę.`]},{day: 23, title: `Telefon i internet`, title_native: `Telefon und Internet`, focus: `W podróży po Niemczech lub Austrii potrzebujesz internetu, ładowarki i czasem lokalnej karty SIM. Dziś nauczysz się technologicznych zwrotów podróżnych.`, vocab: [{de: `Telefon`, pl: `telefon`, ipa: `[te-le-fon]`},{de: `Handy`, pl: `komórka`, ipa: `[hen-di]`},{de: `Internet`, pl: `internet`, ipa: `[in-ter-net]`},{de: `Ladegerät`, pl: `ładowarka`, ipa: `[la-de-ge-ret]`},{de: `Steckdose`, pl: `gniazdko`, ipa: `[sztek-do-ze]`},{de: `Akku`, pl: `bateria`, ipa: `[a-ku]`},{de: `SIM-Karte`, pl: `karta SIM`, ipa: `[sim-kar-te]`},{de: `Passwort`, pl: `hasło`, ipa: `[pas-wort]`},{de: `Nachricht`, pl: `wiadomość`, ipa: `[nah-riśt]`},{de: `Anruf`, pl: `telefon, połączenie`, ipa: `[an-ruf]`}], phrases: [{de: `Mein Akku ist leer.`, pl: `Moja bateria jest rozładowana.`, ipa: `[majn a-ku ist ler]`},{de: `Ich brauche ein Ladegerät.`, pl: `Potrzebuję ładowarki.`, ipa: `[iś brał-he ajn la-de-ge-ret]`},{de: `Gibt es hier WLAN?`, pl: `Czy jest tutaj Wi-Fi?`, ipa: `[gibt es hir we-lan]`},{de: `Wie ist das Passwort?`, pl: `Jakie jest hasło?`, ipa: `[wi ist das pas-wort]`},{de: `Ich möchte eine SIM-Karte kaufen.`, pl: `Chciałbym/chciałabym kupić kartę SIM.`, ipa: `[iś myś-te aj-ne sim-kar-te kał-fen]`},{de: `Kann ich mein Handy hier laden?`, pl: `Czy mogę tutaj naładować telefon?`, ipa: `[kan iś majn hen-di hir la-den]`}], grammar: `„Mein” i „meine” oznaczają „mój/moja”; zapamiętaj gotowe pary: „mein Akku”, „meine SIM-Karte”. „Hier” możesz dodać do wielu pytań, gdy pytasz o możliwość w konkretnym miejscu. „Kann ich...?” jest bardzo praktyczne przy prośbach.`, practice: [`Powiedz, że bateria jest rozładowana.`,`Zapytaj, czy jest Wi-Fi.`,`Zapytaj o hasło.`,`Poproś o możliwość naładowania telefonu.`,`Powiedz, że chcesz kupić kartę SIM.`]},{day: 24, title: `Pieniądze i płatności`, title_native: `Geld und Bezahlen`, focus: `W sklepach i restauracjach w krajach niemieckojęzycznych czasem nadal przydaje się gotówka. Nauczysz się pytać o płatności, bankomat i paragon.`, vocab: [{de: `Geld`, pl: `pieniądze`, ipa: `[gelt]`},{de: `Bargeld`, pl: `gotówka`, ipa: `[bar-gelt]`},{de: `Karte`, pl: `karta`, ipa: `[kar-te]`},{de: `Kreditkarte`, pl: `karta kredytowa`, ipa: `[kre-dit-kar-te]`},{de: `Bankautomat`, pl: `bankomat`, ipa: `[bank-ał-to-mat]`},{de: `Quittung`, pl: `paragon`, ipa: `[kwi-tung]`},{de: `bezahlen`, pl: `płacić`, ipa: `[be-ca-len]`},{de: `wechseln`, pl: `wymieniać`, ipa: `[wek-seln]`},{de: `teuer`, pl: `drogi`, ipa: `[toj-er]`},{de: `billig`, pl: `tani`, ipa: `[bi-liś]`}], phrases: [{de: `Kann ich mit Karte bezahlen?`, pl: `Czy mogę zapłacić kartą?`, ipa: `[kan iś mit kar-te be-ca-len]`},{de: `Nehmen Sie Bargeld?`, pl: `Czy przyjmują państwo gotówkę?`, ipa: `[nej-men zi bar-gelt]`},{de: `Wo ist ein Bankautomat?`, pl: `Gdzie jest bankomat?`, ipa: `[wo ist ajn bank-ał-to-mat]`},{de: `Ich brauche eine Quittung.`, pl: `Potrzebuję paragonu.`, ipa: `[iś brał-he aj-ne kwi-tung]`},{de: `Das ist zu teuer.`, pl: `To jest za drogie.`, ipa: `[das ist cu toj-er]`},{de: `Können Sie Geld wechseln?`, pl: `Czy może pan/pani wymienić pieniądze?`, ipa: `[ky-nen zi gelt wek-seln]`}], grammar: `„Mit Karte” znaczy „kartą”, a „bar” znaczy „gotówką”. W pytaniach o płatność używaj „Kann ich...?” albo „Nehmen Sie...?”. „Quittung” to paragon lub potwierdzenie, przydatne w podróży służbowej.`, practice: [`Zapytaj, czy możesz zapłacić kartą.`,`Zapytaj, czy przyjmują gotówkę.`,`Zapytaj o bankomat.`,`Poproś o paragon.`,`Zapytaj, czy można wymienić pieniądze.`]},{day: 25, title: `Wynajem i rezerwacje`, title_native: `Miete und Reservierungen`, focus: `W podróży możesz rezerwować rower, samochód albo stolik. Dziś nauczysz się mówić o dostępności, czasie i warunkach rezerwacji.`, vocab: [{de: `mieten`, pl: `wynajmować`, ipa: `[mi-ten]`},{de: `reservieren`, pl: `rezerwować`, ipa: `[re-zer-wi-ren]`},{de: `frei`, pl: `wolny, dostępny`, ipa: `[fraj]`},{de: `verfügbar`, pl: `dostępny`, ipa: `[fer-fyg-bar]`},{de: `Stunde`, pl: `godzina`, ipa: `[sztun-de]`},{de: `Tag`, pl: `dzień`, ipa: `[tak]`},{de: `Preis`, pl: `cena`, ipa: `[prajs]`},{de: `Kaution`, pl: `kaucja`, ipa: `[kał-cjon]`},{de: `Ausweis`, pl: `dokument tożsamości`, ipa: `[ałs-wajs]`},{de: `unterschreiben`, pl: `podpisać`, ipa: `[un-ter-szraj-ben]`}], phrases: [{de: `Ich möchte ein Fahrrad mieten.`, pl: `Chciałbym/chciałabym wynająć rower.`, ipa: `[iś myś-te ajn far-rat mi-ten]`},{de: `Ist es heute verfügbar?`, pl: `Czy jest dziś dostępne?`, ipa: `[ist es hoj-te fer-fyg-bar]`},{de: `Was kostet es pro Tag?`, pl: `Ile kosztuje za dzień?`, ipa: `[was kos-tet es pro tak]`},{de: `Brauchen Sie meinen Ausweis?`, pl: `Czy potrzebuje pan/pani mojego dokumentu?`, ipa: `[brał-hen zi maj-nen ałs-wajs]`},{de: `Muss ich eine Kaution zahlen?`, pl: `Czy muszę zapłacić kaucję?`, ipa: `[mus iś aj-ne kał-cjon ca-len]`},{de: `Ich möchte für morgen reservieren.`, pl: `Chciałbym/chciałabym zarezerwować na jutro.`, ipa: `[iś myś-te fyr mor-gen re-zer-wi-ren]`}], grammar: `„Pro Tag” oznacza „za dzień”, a „pro Stunde” — „za godzinę”. Przy rezerwacjach bardzo przydatne jest „Ich möchte...”, bo brzmi uprzejmie i jasno. Pytanie „Muss ich...?” pomaga ustalić obowiązki, np. kaucję.`, practice: [`Powiedz, że chcesz wynająć rower.`,`Zapytaj, czy coś jest dziś dostępne.`,`Zapytaj o cenę za dzień.`,`Zapytaj o kaucję.`,`Zarezerwuj coś na jutro.`]},{day: 26, title: `Na poczcie`, title_native: `Auf der Post`, focus: `Jeśli chcesz wysłać pocztówkę z Wiednia albo paczkę z Berlina, przyda się język poczty. Nauczysz się pytać o znaczki, adres i wysyłkę.`, vocab: [{de: `Post`, pl: `poczta`, ipa: `[post]`},{de: `Brief`, pl: `list`, ipa: `[brif]`},{de: `Postkarte`, pl: `pocztówka`, ipa: `[post-kar-te]`},{de: `Paket`, pl: `paczka`, ipa: `[pa-ket]`},{de: `Briefmarke`, pl: `znaczek`, ipa: `[brif-mar-ke]`},{de: `Adresse`, pl: `adres`, ipa: `[a-dre-se]`},{de: `schicken`, pl: `wysyłać`, ipa: `[szi-ken]`},{de: `ankommen`, pl: `dotrzeć`, ipa: `[an-ko-men]`},{de: `Luftpost`, pl: `poczta lotnicza`, ipa: `[luft-post]`},{de: `Unterschrift`, pl: `podpis`, ipa: `[un-ter-szrift]`}], phrases: [{de: `Ich möchte eine Postkarte schicken.`, pl: `Chciałbym/chciałabym wysłać pocztówkę.`, ipa: `[iś myś-te aj-ne post-kar-te szi-ken]`},{de: `Eine Briefmarke nach Polen, bitte.`, pl: `Znaczek do Polski, proszę.`, ipa: `[aj-ne brif-mar-ke nah po-len, bi-te]`},{de: `Wie lange dauert das?`, pl: `Ile to potrwa?`, ipa: `[wi lan-ge dał-ert das]`},{de: `Ist die Adresse richtig?`, pl: `Czy adres jest poprawny?`, ipa: `[ist di a-dre-se riś-tiś]`},{de: `Ich möchte dieses Paket schicken.`, pl: `Chciałbym/chciałabym wysłać tę paczkę.`, ipa: `[iś myś-te di-zes pa-ket szi-ken]`},{de: `Brauchen Sie eine Unterschrift?`, pl: `Czy potrzebuje pan/pani podpisu?`, ipa: `[brał-hen zi aj-ne un-ter-szrift]`}], grammar: `„Nach Polen” znaczy „do Polski”, ale przy miastach mówi się zwykle „nach Berlin”, „nach Wien”. „Schicken” to praktyczny czasownik na poczcie i w wiadomościach. „Dieses” oznacza „to/ten” przy wskazywaniu konkretnej rzeczy.`, practice: [`Powiedz, że chcesz wysłać pocztówkę.`,`Poproś o znaczek do Polski.`,`Zapytaj, ile potrwa wysyłka.`,`Zapytaj, czy adres jest poprawny.`,`Powiedz, że chcesz wysłać paczkę.`]},{day: 27, title: `Praca z aplikacjami podróżnymi`, title_native: `Reise-Apps benutzen`, focus: `Podczas podróży po Berlinie albo Wiedniu często używasz map, aplikacji biletowych i tłumacza. Nauczysz się rozmawiać o aplikacjach i problemach technicznych.`, vocab: [{de: `App`, pl: `aplikacja`, ipa: `[ep]`},{de: `Karte`, pl: `mapa`, ipa: `[kar-te]`},{de: `Übersetzer`, pl: `tłumacz`, ipa: `[y-ber-zet-ser]`},{de: `Download`, pl: `pobieranie`, ipa: `[dałn-lod]`},{de: `Verbindung`, pl: `połączenie`, ipa: `[fer-bin-dung]`},{de: `Standort`, pl: `lokalizacja`, ipa: `[sztant-ort]`},{de: `öffnen`, pl: `otwierać`, ipa: `[yf-nen]`},{de: `funktionieren`, pl: `działać`, ipa: `[funk-cjo-ni-ren]`},{de: `aktualisieren`, pl: `aktualizować`, ipa: `[ak-tu-a-li-zi-ren]`},{de: `anzeigen`, pl: `pokazywać`, ipa: `[an-caj-gen]`}], phrases: [{de: `Die App funktioniert nicht.`, pl: `Aplikacja nie działa.`, ipa: `[di ep funk-cjo-nirt niśt]`},{de: `Können Sie mir die Route zeigen?`, pl: `Czy może pan/pani pokazać mi trasę?`, ipa: `[ky-nen zi mir di ru-te caj-gen]`},{de: `Ich habe keine Verbindung.`, pl: `Nie mam połączenia.`, ipa: `[iś ha-be kaj-ne fer-bin-dung]`},{de: `Muss ich die App aktualisieren?`, pl: `Czy muszę zaktualizować aplikację?`, ipa: `[mus iś di ep ak-tu-a-li-zi-ren]`},{de: `Mein Standort ist falsch.`, pl: `Moja lokalizacja jest błędna.`, ipa: `[majn sztant-ort ist falsz]`},{de: `Kann ich das Ticket in der App zeigen?`, pl: `Czy mogę pokazać bilet w aplikacji?`, ipa: `[kan iś das ti-ket in der ep caj-gen]`}], grammar: `„Keine” zaprzecza rzeczownik rodzaju żeńskiego lub liczby mnogiej: „keine Verbindung”. Przy problemach technicznych możesz używać prostego schematu: rzecz + „funktioniert nicht”. To wystarczy, aby ktoś zrozumiał problem.`, practice: [`Powiedz, że aplikacja nie działa.`,`Powiedz, że nie masz połączenia.`,`Zapytaj, czy musisz zaktualizować aplikację.`,`Zapytaj, czy możesz pokazać bilet w aplikacji.`,`Poproś o pokazanie trasy.`]},{day: 28, title: `Zaproszenia i plany`, title_native: `Einladungen und Pläne`, focus: `Kiedy poznasz kogoś w kawiarni w Hamburgu albo na wycieczce w Wiedniu, możesz chcieć zaproponować spotkanie. Dziś ćwiczysz zaproszenia i odpowiedzi.`, vocab: [{de: `treffen`, pl: `spotykać`, ipa: `[tre-fen]`},{de: `einladen`, pl: `zapraszać`, ipa: `[ajn-la-den]`},{de: `Plan`, pl: `plan`, ipa: `[plan]`},{de: `Zeit`, pl: `czas`, ipa: `[cajt]`},{de: `Lust`, pl: `ochota`, ipa: `[lust]`},{de: `Kaffee`, pl: `kawa`, ipa: `[ka-fe]`},{de: `Abendessen`, pl: `kolacja`, ipa: `[a-bent-e-sen]`},{de: `spazieren`, pl: `spacerować`, ipa: `[szpa-ci-ren]`},{de: `morgen`, pl: `jutro`, ipa: `[mor-gen]`},{de: `vielleicht`, pl: `może`, ipa: `[fi-lajśt]`}], phrases: [{de: `Haben Sie heute Zeit?`, pl: `Czy ma pan/pani dziś czas?`, ipa: `[ha-ben zi hoj-te cajt]`},{de: `Hast du Lust auf Kaffee?`, pl: `Masz ochotę na kawę?`, ipa: `[hast du lust ałf ka-fe]`},{de: `Wollen wir spazieren gehen?`, pl: `Może pójdziemy na spacer?`, ipa: `[wo-len wir szpa-ci-ren ge-en]`},{de: `Ich lade dich ein.`, pl: `Zapraszam cię, ja stawiam.`, ipa: `[iś la-de diś ajn]`},{de: `Vielleicht morgen.`, pl: `Może jutro.`, ipa: `[fi-lajśt mor-gen]`},{de: `Das klingt gut.`, pl: `To brzmi dobrze.`, ipa: `[das klinkt gut]`}], grammar: `„Haben Sie...” jest formalne, a „Hast du...” swobodne. „Lust auf...” oznacza „ochotę na...”, np. „Lust auf Kaffee”. W kontaktach towarzyskich szybko przechodzi się na „du”, ale poczekaj, aż sytuacja będzie luźna.`, practice: [`Zapytaj formalnie, czy ktoś ma dziś czas.`,`Zaproponuj kawę nieformalnie.`,`Zaproponuj spacer.`,`Powiedz, że brzmi dobrze.`,`Odpowiedz „może jutro”.`]},{day: 29, title: `Opinie i preferencje`, title_native: `Meinungen und Vorlieben`, focus: `W rozmowach z lokalnymi mieszkańcami chcesz powiedzieć, co lubisz, czego nie lubisz i co myślisz. Nauczysz się prostych opinii o mieście, jedzeniu i planach.`, vocab: [{de: `mögen`, pl: `lubić`, ipa: `[my-gen]`},{de: `lieben`, pl: `kochać, bardzo lubić`, ipa: `[li-ben]`},{de: `finden`, pl: `uważać, znajdować`, ipa: `[fin-den]`},{de: `denken`, pl: `myśleć`, ipa: `[den-ken]`},{de: `gut`, pl: `dobry`, ipa: `[gut]`},{de: `schlecht`, pl: `zły`, ipa: `[szleśt]`},{de: `schön`, pl: `ładny`, ipa: `[szyn]`},{de: `teuer`, pl: `drogi`, ipa: `[toj-er]`},{de: `ruhig`, pl: `spokojny`, ipa: `[ru-iś]`},{de: `voll`, pl: `pełny, zatłoczony`, ipa: `[fol]`}], phrases: [{de: `Ich mag diese Stadt.`, pl: `Lubię to miasto.`, ipa: `[iś mak di-ze sztat]`},{de: `Ich finde das sehr schön.`, pl: `Uważam, że to jest bardzo ładne.`, ipa: `[iś fin-de das zejr szyn]`},{de: `Das Essen ist gut.`, pl: `Jedzenie jest dobre.`, ipa: `[das e-sen ist gut]`},{de: `Es ist hier zu voll.`, pl: `Tutaj jest za tłoczno.`, ipa: `[es ist hir cu fol]`},{de: `Ich denke, das ist teuer.`, pl: `Myślę, że to jest drogie.`, ipa: `[iś den-ke, das ist toj-er]`},{de: `Ich liebe diese Aussicht.`, pl: `Uwielbiam ten widok.`, ipa: `[iś li-be di-ze ałs-ziśt]`}], grammar: `„Ich finde...” często tłumaczymy jako „uważam, że...”, nie tylko „znajduję”. To bardzo naturalny sposób wyrażania opinii. Po „ich denke” możesz dodać pełne zdanie: „Ich denke, das ist teuer”.`, practice: [`Powiedz, że lubisz to miasto.`,`Powiedz, że jedzenie jest dobre.`,`Powiedz, że tutaj jest za tłoczno.`,`Wyraź opinię, że coś jest drogie.`,`Powiedz, że uwielbiasz widok.`]},{day: 30, title: `Pełny dzień w podróży`, title_native: `Ein ganzer Reisetag`, focus: `Ostatniego dnia łączysz wszystko: hotel, transport, jedzenie, pytania i rozmowy. Wyobraź sobie pełny dzień w Wiedniu od śniadania do powrotu do hotelu.`, vocab: [{de: `Reisetag`, pl: `dzień podróży`, ipa: `[raj-ze-tak]`},{de: `Plan`, pl: `plan`, ipa: `[plan]`},{de: `Frühstück`, pl: `śniadanie`, ipa: `[fry-sztyk]`},{de: `Ticket`, pl: `bilet`, ipa: `[ti-ket]`},{de: `Museum`, pl: `muzeum`, ipa: `[mu-ze-um]`},{de: `Mittagessen`, pl: `obiad`, ipa: `[mi-tak-e-sen]`},{de: `Pause`, pl: `przerwa`, ipa: `[pał-ze]`},{de: `Rückweg`, pl: `droga powrotna`, ipa: `[ryk-wek]`},{de: `müde`, pl: `zmęczony`, ipa: `[my-de]`},{de: `zufrieden`, pl: `zadowolony`, ipa: `[cu-fri-den]`}], phrases: [{de: `Heute habe ich viel vor.`, pl: `Dziś mam dużo planów.`, ipa: `[hoj-te ha-be iś fil for]`},{de: `Zuerst frühstücke ich.`, pl: `Najpierw jem śniadanie.`, ipa: `[cu-erst fry-szty-ke iś]`},{de: `Dann kaufe ich ein Ticket.`, pl: `Potem kupuję bilet.`, ipa: `[dan kał-fe iś ajn ti-ket]`},{de: `Nach dem Museum mache ich eine Pause.`, pl: `Po muzeum zrobię przerwę.`, ipa: `[nah dem mu-ze-um ma-he iś aj-ne pał-ze]`},{de: `Ich gehe zurück zum Hotel.`, pl: `Wracam do hotelu.`, ipa: `[iś ge-e cu-ryk cum ho-tel]`},{de: `Ich bin müde, aber zufrieden.`, pl: `Jestem zmęczony, ale zadowolony.`, ipa: `[iś bin my-de, a-ber cu-fri-den]`}], grammar: `„Zuerst”, „dann” i „nach dem...” pomagają opowiadać plan dnia w kolejności. W zdaniu „Zuerst frühstücke ich” czasownik pozostaje na drugim miejscu. To typowy niemiecki szyk, który warto ćwiczyć w krótkich opowieściach.`, practice: [`Opowiedz po niemiecku pierwszy krok swojego dnia.`,`Powiedz, że potem kupujesz bilet.`,`Powiedz, że po muzeum robisz przerwę.`,`Powiedz, że wracasz do hotelu.`,`Ułóż trzyzdaniowy plan dnia z „zuerst”, „dann” i „nach dem”.`]}];

var CONVERSATIONS_PL_DE = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w kawiarni w Berlinie rano przed zwiedzaniem. Chcesz zamówić kawę, wodę i kawałek ciasta.`, lines: [{who: `them`, de: `Guten Morgen, was möchten Sie?`, pl: `Dzień dobry, czego pan/pani sobie życzy?`},{who: `you`, de: `Guten Morgen, einen Kaffee, bitte.`, pl: `Dzień dobry, kawę, proszę.`},{who: `them`, de: `Mit Milch und Zucker?`, pl: `Z mlekiem i cukrem?`},{who: `you`, de: `Mit Milch, aber ohne Zucker, bitte.`, pl: `Z mlekiem, ale bez cukru, proszę.`},{who: `them`, de: `Möchten Sie auch etwas essen?`, pl: `Czy chce pan/pani też coś zjeść?`},{who: `you`, de: `Ja, ein Stück Kuchen, bitte.`, pl: `Tak, kawałek ciasta, proszę.`},{who: `them`, de: `Noch etwas?`, pl: `Coś jeszcze?`},{who: `you`, de: `Ein Glas Wasser, bitte.`, pl: `Szklankę wody, proszę.`},{who: `them`, de: `Zum Mitnehmen oder hier?`, pl: `Na wynos czy tutaj?`},{who: `you`, de: `Hier, bitte.`, pl: `Tutaj, proszę.`},{who: `them`, de: `Das macht acht Euro.`, pl: `To będzie osiem euro.`},{who: `you`, de: `Danke schön.`, pl: `Bardzo dziękuję.`}]},{id: 2, title: `Meldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Monachium. Masz rezerwację i chcesz zapytać o śniadanie oraz Wi-Fi.`, lines: [{who: `them`, de: `Guten Abend, willkommen im Hotel.`, pl: `Dobry wieczór, witamy w hotelu.`},{who: `you`, de: `Guten Abend, ich möchte einchecken.`, pl: `Dobry wieczór, chciałbym/chciałabym się zameldować.`},{who: `them`, de: `Haben Sie eine Reservierung?`, pl: `Czy ma pan/pani rezerwację?`},{who: `you`, de: `Ja, ich habe eine Reservierung auf den Namen Kowalski.`, pl: `Tak, mam rezerwację na nazwisko Kowalski.`},{who: `them`, de: `Darf ich Ihren Pass sehen?`, pl: `Czy mogę zobaczyć pana/pani paszport?`},{who: `you`, de: `Natürlich, hier ist mein Pass.`, pl: `Oczywiście, oto mój paszport.`},{who: `them`, de: `Ihr Zimmer ist in der dritten Etage.`, pl: `Pana/pani pokój jest na trzecim piętrze.`},{who: `you`, de: `Ist Frühstück inklusive?`, pl: `Czy śniadanie jest w cenie?`},{who: `them`, de: `Ja, Frühstück ist von sieben bis zehn Uhr.`, pl: `Tak, śniadanie jest od siódmej do dziesiątej.`},{who: `you`, de: `Wie ist das WLAN-Passwort?`, pl: `Jakie jest hasło do Wi-Fi?`},{who: `them`, de: `Das Passwort steht auf der Karte.`, pl: `Hasło jest na karcie.`},{who: `you`, de: `Danke, gute Nacht.`, pl: `Dziękuję, dobranoc.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Jesteś w Wiedniu i szukasz starego miasta. Zatrzymujesz przechodnia i prosisz o proste wskazówki.`, lines: [{who: `you`, de: `Entschuldigung, können Sie mir helfen?`, pl: `Przepraszam, czy może mi pan/pani pomóc?`},{who: `them`, de: `Ja, natürlich.`, pl: `Tak, oczywiście.`},{who: `you`, de: `Wo ist die Altstadt?`, pl: `Gdzie jest stare miasto?`},{who: `them`, de: `Gehen Sie geradeaus und dann links.`, pl: `Proszę iść prosto, a potem w lewo.`},{who: `you`, de: `Ist es weit von hier?`, pl: `Czy to daleko stąd?`},{who: `them`, de: `Nein, ungefähr zehn Minuten zu Fuß.`, pl: `Nie, około dziesięć minut pieszo.`},{who: `you`, de: `Gibt es dort ein Museum?`, pl: `Czy jest tam muzeum?`},{who: `them`, de: `Ja, es gibt viele Museen in der Nähe.`, pl: `Tak, w pobliżu jest wiele muzeów.`},{who: `you`, de: `Danke schön.`, pl: `Bardzo dziękuję.`},{who: `them`, de: `Gern, schönen Tag noch.`, pl: `Proszę, miłego dnia.`},{who: `you`, de: `Ihnen auch.`, pl: `Panu/pani również.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w restauracji w Salzburgu. Chcesz stolik, pytasz o rekomendację i prosisz o rachunek.`, lines: [{who: `them`, de: `Guten Abend, haben Sie reserviert?`, pl: `Dobry wieczór, czy mają państwo rezerwację?`},{who: `you`, de: `Nein, einen Tisch für zwei, bitte.`, pl: `Nie, stolik dla dwóch osób, proszę.`},{who: `them`, de: `Natürlich, bitte hier.`, pl: `Oczywiście, proszę tutaj.`},{who: `you`, de: `Danke, die Speisekarte bitte.`, pl: `Dziękuję, kartę dań proszę.`},{who: `them`, de: `Hier ist die Speisekarte.`, pl: `Oto karta dań.`},{who: `you`, de: `Was empfehlen Sie?`, pl: `Co pan/pani poleca?`},{who: `them`, de: `Der Fisch ist heute sehr gut.`, pl: `Ryba jest dziś bardzo dobra.`},{who: `you`, de: `Gut, ich nehme den Fisch.`, pl: `Dobrze, wezmę rybę.`},{who: `them`, de: `Möchten Sie etwas trinken?`, pl: `Czy chce pan/pani coś do picia?`},{who: `you`, de: `Ein Glas Wasser, bitte.`, pl: `Szklankę wody, proszę.`},{who: `them`, de: `Sehr gern.`, pl: `Oczywiście.`},{who: `you`, de: `Später bitte die Rechnung.`, pl: `Później poproszę rachunek.`}]},{id: 5, title: `Kupowanie biletu na transport`, scene: `Jesteś na stacji metra w Berlinie. Chcesz kupić bilet do centrum i upewnić się, którą linią jechać.`, lines: [{who: `them`, de: `Guten Tag, brauchen Sie Hilfe?`, pl: `Dzień dobry, czy potrzebuje pan/pani pomocy?`},{who: `you`, de: `Ja, ich brauche ein Ticket zum Zentrum.`, pl: `Tak, potrzebuję biletu do centrum.`},{who: `them`, de: `Einfach oder für den ganzen Tag?`, pl: `Jednorazowy czy na cały dzień?`},{who: `you`, de: `Für den ganzen Tag, bitte.`, pl: `Na cały dzień, proszę.`},{who: `them`, de: `Das kostet neun Euro.`, pl: `To kosztuje dziewięć euro.`},{who: `you`, de: `Kann ich mit Karte bezahlen?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, de: `Ja, natürlich.`, pl: `Tak, oczywiście.`},{who: `you`, de: `Welche Linie fährt zum Zentrum?`, pl: `Która linia jedzie do centrum?`},{who: `them`, de: `Nehmen Sie die U-Bahn Linie zwei.`, pl: `Proszę wziąć metro linii dwa.`},{who: `you`, de: `In welche Richtung?`, pl: `W którym kierunku?`},{who: `them`, de: `Richtung Alexanderplatz.`, pl: `W kierunku Alexanderplatz.`},{who: `you`, de: `Vielen Dank.`, pl: `Bardzo dziękuję.`}]},{id: 6, title: `Zakupy w sklepie`, scene: `Jesteś w sklepie odzieżowym w Düsseldorfie. Szukasz czarnych spodni, chcesz sprawdzić rozmiar i zapytać o przymierzalnię.`, lines: [{who: `them`, de: `Hallo, kann ich Ihnen helfen?`, pl: `Dzień dobry, czy mogę pomóc?`},{who: `you`, de: `Ja, ich suche eine schwarze Hose.`, pl: `Tak, szukam czarnych spodni.`},{who: `them`, de: `Welche Größe brauchen Sie?`, pl: `Jakiego rozmiaru pan/pani potrzebuje?`},{who: `you`, de: `Haben Sie diese Größe?`, pl: `Czy ma pan/pani ten rozmiar?`},{who: `them`, de: `Ja, hier bitte.`, pl: `Tak, proszę.`},{who: `you`, de: `Wo ist die Umkleidekabine?`, pl: `Gdzie jest przymierzalnia?`},{who: `them`, de: `Dort links.`, pl: `Tam po lewej.`},{who: `you`, de: `Danke, ich probiere sie an.`, pl: `Dziękuję, przymierzę je.`},{who: `them`, de: `Passt die Hose?`, pl: `Czy spodnie pasują?`},{who: `you`, de: `Ja, das passt gut.`, pl: `Tak, dobrze pasują.`},{who: `them`, de: `Möchten Sie sie kaufen?`, pl: `Czy chce je pan/pani kupić?`},{who: `you`, de: `Ja, ich nehme sie.`, pl: `Tak, wezmę je.`}]},{id: 7, title: `W aptece`, scene: `Jesteś w aptece w Zurychu, bo boli cię głowa i masz kaszel. Chcesz kupić lek bez recepty.`, lines: [{who: `them`, de: `Guten Tag, wie kann ich helfen?`, pl: `Dzień dobry, jak mogę pomóc?`},{who: `you`, de: `Guten Tag, ich habe Kopfschmerzen.`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, de: `Haben Sie auch Fieber?`, pl: `Czy ma pan/pani też gorączkę?`},{who: `you`, de: `Nein, aber ich habe Husten.`, pl: `Nie, ale mam kaszel.`},{who: `them`, de: `Ich empfehle dieses Medikament.`, pl: `Polecam ten lek.`},{who: `you`, de: `Ist das rezeptfrei?`, pl: `Czy to jest bez recepty?`},{who: `them`, de: `Ja, das ist rezeptfrei.`, pl: `Tak, to jest bez recepty.`},{who: `you`, de: `Wie oft nehme ich es?`, pl: `Jak często mam to brać?`},{who: `them`, de: `Zweimal am Tag mit Wasser.`, pl: `Dwa razy dziennie z wodą.`},{who: `you`, de: `Haben Sie auch Pflaster?`, pl: `Czy ma pan/pani też plastry?`},{who: `them`, de: `Ja, hier sind Pflaster.`, pl: `Tak, oto plastry.`},{who: `you`, de: `Danke schön.`, pl: `Bardzo dziękuję.`}]},{id: 8, title: `Small talk z lokalną osobą`, scene: `Siedzisz w parku w Hamburgu i rozmawiasz z lokalną osobą. Rozmowa jest swobodna, dotyczy miasta, podróży i planów.`, lines: [{who: `you`, de: `Hallo, ist dieser Platz frei?`, pl: `Cześć, czy to miejsce jest wolne?`},{who: `them`, de: `Ja, natürlich.`, pl: `Tak, oczywiście.`},{who: `you`, de: `Danke, die Stadt ist sehr schön.`, pl: `Dziękuję, miasto jest bardzo piękne.`},{who: `them`, de: `Sind Sie im Urlaub hier?`, pl: `Czy jest pan/pani tutaj na wakacjach?`},{who: `you`, de: `Ja, ich komme aus Polen.`, pl: `Tak, pochodzę z Polski.`},{who: `them`, de: `Wie gefällt Ihnen Hamburg?`, pl: `Jak podoba się panu/pani Hamburg?`},{who: `you`, de: `Ich finde Hamburg interessant und freundlich.`, pl: `Uważam, że Hamburg jest interesujący i przyjazny.`},{who: `them`, de: `Haben Sie heute noch Pläne?`, pl: `Czy ma pan/pani jeszcze dziś plany?`},{who: `you`, de: `Ja, ich möchte zum Hafen gehen.`, pl: `Tak, chcę iść do portu.`},{who: `them`, de: `Das ist eine gute Idee.`, pl: `To dobry pomysł.`},{who: `you`, de: `Danke, es war nett, Sie kennenzulernen.`, pl: `Dziękuję, miło było pana/panią poznać.`},{who: `them`, de: `Ebenso, viel Spaß in Hamburg.`, pl: `Nawzajem, miłego pobytu w Hamburgu.`}]}];